10	export class InterfaceDeclaration extends TypeBuilder {
11	  needsParenthesisWhenIndexed = true
12	
13	  private items: InterfaceItem[] = []
14	  private genericParameters: GenericParameter[] = []
15	  private extendedTypes: NamedType[] = []
16	
17	  constructor(readonly name: string) {
18	    super()
19	  }
20	
21	  add(item: InterfaceItem): this {
22	    this.items.push(item)
23	    return this
24	  }
25	
26	  addMultiple(items: InterfaceItem[]): this {
27	    for (const item of items) {
28	      this.add(item)
29	    }
30	    return this
31	  }
32	
33	  addGenericParameter(param: GenericParameter) {
34	    this.genericParameters.push(param)
35	    return this
36	  }
37	
38	  extends(type: NamedType) {
39	    this.extendedTypes.push(type)
40	    return this
41	  }
42	
43	  write(writer: Writer): void {
44	    writer.write('interface ').write(this.name)
45	    if (this.genericParameters.length > 0) {
46	      writer.write('<').writeJoined(', ', this.genericParameters).write('>')
47	    }
48	
49	    if (this.extendedTypes.length > 0) {
50	      writer.write(' extends ').writeJoined(', ', this.extendedTypes)
51	    }
52	    if (this.items.length === 0) {
53	      writer.writeLine(' {}')
54	      return
55	    }
56	
57	    writer
58	      .writeLine(' {')
59	      .withIndent(() => {
60	        for (const item of this.items) {
61	          writer.writeLine(item)
62	        }
63	      })
64	      .write('}')
65	  }
66	}
