4	export class UnionType<VariantType extends TypeBuilder = TypeBuilder> extends TypeBuilder {
5	  needsParenthesisWhenIndexed = true
6	  needsParenthesisInKeyof = true
7	  needsParenthesisInIntersection = true
8	  readonly variants: VariantType[]
9	
10	  constructor(firstType: VariantType) {
11	    super()
12	    this.variants = [firstType]
13	  }
14	
15	  addVariant(variant: VariantType) {
16	    this.variants.push(variant)
17	    return this
18	  }
19	
20	  addVariants(variants: VariantType[]) {
21	    for (const variant of variants) {
22	      this.addVariant(variant)
23	    }
24	    return this
25	  }
26	
27	  write(writer: Writer): void {
