### **6. MODEL/FIELD ITERATION PATTERN**

From `packages/client-generator-ts/src/TSClient/TSClient.ts`:

```typescript
generateClientFiles(): FileMap {
  const context = new GenerateContext({
    dmmf: this.dmmf,
    genericArgsInfo: this.genericsInfo,
    runtimeBase: this.options.runtimeBase,
    runtimeImport: `${this.options.runtimeBase}/${this.options.runtimeName}`,
    outputFileName: generatedFileNameMapper(this.options.generatedFileExtension),
    importFileName: importFileNameMapper(this.options.importFileExtension),
    generator: this.options.generator,
    provider: this.options.activeProvider,
  })

  // Get all models that have output types
  const modelNames = Object.values(context.dmmf.typeAndModelMap)
    .filter((model) => context.dmmf.outputTypeMap.model[model.name])
    .map((model) => model.name)

  // Generate one file per model
  const modelsFileMap: FileMap = modelNames.reduce((acc, modelName) => {
    acc[context.outputFileName(modelName)] = createModelFile(context, modelName)
    return acc
  }, {})

  return {
    [context.outputFileName('client')]: createClientFile(context, this.options),
    [context.outputFileName('enums')]: createEnumsFile(context),
    models: modelsFileMap,
    internal: { /* ... */ },
  }
}
```

#### **Model Class Pattern:**

```typescript
// packages/client-generator-ts/src/TSClient/Model.ts
export class Model {
  private type: DMMF.OutputType
  private mapping?: DMMF.ModelMapping
  private dmmf: DMMFHelper

  constructor(
    private readonly model: DMMF.Model,
    private readonly context: GenerateContext,
  ) {
    this.dmmf = context.dmmf
    this.type = this.context.dmmf.outputTypeMap.model[model.name]
    this.mapping = this.context.dmmf.mappings.modelOperations.find((m) => m.model === model.name)!
  }

  private get argsTypes(): ts.Export<ts.TypeDeclaration>[] {
    const argsTypes: ts.Export<ts.TypeDeclaration>[] = []

    for (const action of Object.keys(DMMF.ModelAction)) {
      const fieldName = this.rootFieldNameForAction(action as DMMF.ModelAction)
      if (!fieldName) continue

      const field = this.dmmf.rootFieldMap[fieldName]
      if (!field) {
        throw new Error(`Could not find field ${fieldName}`)
      }

      argsTypes.push(
        new ArgsTypeBuilder(this.type, this.context, action as DMMF.ModelAction)
          .addSchemaArgs(field.args)
          .createExport(),
      )
    }

    return argsTypes
  }
}
