import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

Matches `packages/adapter-pg/helpers/build.ts` exactly.

---

### Step 5 — `packages/generator-rest-client/src/utils/prisma-type-map.ts`

This module maps DMMF scalar type strings to TypeScript type strings.

```ts
/**
 * Maps Prisma scalar type names to their TypeScript equivalents.
 * Enums and relation types (kind !== 'scalar') are handled separately.
 */
export const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'Date',
  Json: 'unknown',
  BigInt: 'bigint',
  Bytes: 'Uint8Array',
  Decimal: 'string',
}

/**
 * Returns the TypeScript type string for a DMMF scalar field type.
 * Falls back to 'unknown' for unrecognised types (e.g. new Prisma scalars).
 */
export function scalarToTs(prismaType: string): string {
  return PRISMA_SCALAR_TO_TS[prismaType] ?? 'unknown'
}
```

---

### Step 6 — `packages/generator-rest-client/src/utils/naming.ts`

Utility for pluralization and URL-path derivation. This module keeps things simple: a basic lowercase-pluralize heuristic is sufficient for a generator demo.

```ts
/**
 * Converts a PascalCase model name to a camelCase property name.
 * e.g. "UserProfile" → "userProfiles"
 */
export function toCamelPlural(name: string): string {
  const lower = name.charAt(0).toLowerCase() + name.slice(1)
  return pluralize(lower)
}

/**
 * Converts a PascalCase model name to a kebab-case URL segment (plural).
 * e.g. "UserProfile" → "user-profiles"
 */
export function toUrlPath(name: string): string {
  // Convert PascalCase → kebab-case, then pluralize
  const kebab = name
    .replace(/([A-Z])/g, (m, i) => (i === 0 ? m.toLowerCase() : '-' + m.toLowerCase()))
  return pluralize(kebab)
}

/**
 * Minimal English pluralizer for common suffixes.
 * Handles: -s, -es, -ies patterns. Good enough for model names.
 */
export function pluralize(word: string): string {
  if (word.endsWith('y') && !word.endsWith('ay') && !word.endsWith('ey') && !word.endsWith('oy') && !word.endsWith('uy')) {
    return word.slice(0, -1) + 'ies'
  }
  if (word.endsWith('s') || word.endsWith('x') || word.endsWith('z') || word.endsWith('ch') || word.endsWith('sh')) {
    return word + 'es'
  }
  return word + 's'
}
```

Edge cases handled:
- `User` → `users`, `Post` → `posts`, `Category` → `categories`, `Address` → `addresses`
- Models ending in vowel+y (e.g. `Monkey` → `monkeys`, not `monkies`) handled by the vowel-before-y guard

---

### Step 7 — `packages/generator-rest-client/src/code-generators/model-types.ts`

This module generates the content of the `{ModelName}.ts` file (interfaces for base type, create/update/whereUnique inputs). Uses pure template strings.

```ts
import type * as DMMF from '@prisma/dmmf'
import { scalarToTs } from '../utils/prisma-type-map'

/**
 * Returns the TypeScript type annotation string for a single DMMF field.
 * Handles: scalars, enums, lists, optional (non-required + no default).
 * Excludes relation fields (kind === 'object').
 */
function fieldTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'enum') {
    base = field.type  // reference the enum name directly
  } else {
    // 'unsupported' or unknown — emit unknown
    base = 'unknown'
  }
  if (field.isList) {
    base = `${base}[]`
  }
  if (!field.isRequired) {
    base = `${base} | null`
  }
  return base
}

/**
 * Generates the full content of `{ModelName}.ts`.
 *
 * Emits:
 *   - Base interface (scalar + enum fields only, relations excluded)
 *   - CreateInput interface (required fields minus id/autoincrement, optional nullable fields)
 *   - UpdateInput interface (all writable fields optional)
 *   - WhereUniqueInput interface (all @id and @unique fields, all optional)
 */
export function generateModelTypes(model: DMMF.Model): string {
  const scalarAndEnumFields = model.fields.filter(
    (f) => f.kind === 'scalar' || f.kind === 'enum'
  )

  // ---- Base interface ----
  const baseFields = scalarAndEnumFields
    .map((f) => {
      const tsType = fieldTsType(f)
      return `  ${f.name}: ${tsType}`
    })
    .join('\n')

  // ---- CreateInput: exclude fields that have autoincrement/default id, include rest ----
  // Heuristic: if field isId AND hasDefaultValue, it's auto-generated — skip from create input.
  // If field is required and NOT auto-generated id: required in create.
  // If field is not required (nullable): optional in create (type includes null).
  const createFields = scalarAndEnumFields
    .filter((f) => !(f.isId && f.hasDefaultValue))
    .map((f) => {
      if (f.isRequired) {
        return `  ${f.name}: ${fieldTsType(f)}`
      } else {
        // Optional nullable field — make the property optional with `?`
        // Type is already `T | null` from fieldTsType, we add `?`
        return `  ${f.name}?: ${fieldTsType(f)}`
      }
    })
    .join('\n')

  // ---- UpdateInput: all writable fields are optional ----
  // Exclude auto-id fields from update (they are immutable)
  const updateFields = scalarAndEnumFields
    .filter((f) => !(f.isId && f.hasDefaultValue))
    .map((f) => `  ${f.name}?: ${fieldTsType(f)}`)
    .join('\n')

  // ---- WhereUniqueInput: @id and @unique fields ----
  // Also include fields that appear in model.uniqueFields (composite uniques) — take first field
  const uniqueFields = scalarAndEnumFields.filter((f) => f.isId || f.isUnique)
  // If no unique fields found (edge case), fall back to all scalar fields as optional
  const whereFields = (uniqueFields.length > 0 ? uniqueFields : scalarAndEnumFields)
    .map((f) => `  ${f.name}?: ${fieldTsType(f).replace(' | null', '')}`)
    .join('\n')

  const lines: string[] = []

  lines.push(`export interface ${model.name} {`)
  if (baseFields) lines.push(baseFields)
  lines.push(`}`)
  lines.push(``)
  lines.push(`export interface ${model.name}CreateInput {`)
  if (createFields) lines.push(createFields)
  lines.push(`}`)
  lines.push(``)
  lines.push(`export interface ${model.name}UpdateInput {`)
  if (updateFields) lines.push(updateFields)
  lines.push(`}`)
  lines.push(``)
  lines.push(`export interface ${model.name}WhereUniqueInput {`)
  if (whereFields) lines.push(whereFields)
  lines.push(`}`)

  return lines.join('\n') + '\n'
}
```

Edge cases:
- A model with no `@id` and no `@unique` fields still gets a `WhereUniqueInput` (falls back to all scalar fields, all optional).
- Fields with `kind === 'unsupported'` map to `unknown`.
- Enum fields reference the enum name; enum declarations are generated separately in `generate.ts`.
- Relation fields (`kind === 'object'`) are excluded from all interfaces. The spec mentions optionally including them in create/update args, but this is deferred — keeping the base implementation simpler.

---

### Step 8 — `packages/generator-rest-client/src/code-generators/model-client.ts`

Generates the `{ModelName}Client.ts` file using template strings.

```ts
import type * as DMMF from '@prisma/dmmf'
import { toUrlPath } from '../utils/naming'

/**
 * Generates the content of `{ModelName}Client.ts`.
 * Contains a class with findMany, findUnique, create, update, delete methods.
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const urlPath = toUrlPath(name)

  return `\
import type { ${name}, ${name}CreateInput, ${name}UpdateInput, ${name}WhereUniqueInput } from './${name}'

export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`)
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const params = new URLSearchParams(where as Record<string, string>)
    const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`)
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    const results = await res.json() as ${name}[]
    return results[0] ?? null
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)
    return res.json() as Promise<${name}>
  }
}
`
}
```

The template string uses a `\` at the start to avoid a leading newline. All template literal backticks inside the string content are properly escaped as `\``. The `fetch` global is available in Node 18+ (which this repo targets at ES2022).

---

### Step 9 — `packages/generator-rest-client/src/code-generators/rest-api-client.ts`

Generates the barrel `index.ts` for the emitted output directory.

```ts
import type * as DMMF from '@prisma/dmmf'
import { toCamelPlural } from '../utils/naming'

/**
 * Generates the `index.ts` file that:
 * 1. Re-exports all type interfaces from each model file
 * 2. Re-exports each model client class
 * 3. Provides a RestApiClient aggregate class
 */
export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  const exportLines: string[] = []
  const constructorProps: string[] = []
  const constructorAssignments: string[] = []

  for (const model of models) {
    const name = model.name
    const propName = toCamelPlural(name)

    exportLines.push(
      `export type { ${name}, ${name}CreateInput, ${name}UpdateInput, ${name}WhereUniqueInput } from './${name}'`
    )
    exportLines.push(`export { ${name}Client } from './${name}Client'`)

    constructorProps.push(`  readonly ${propName}: ${name}Client`)
    constructorAssignments.push(`    this.${propName} = new ${name}Client(baseUrl)`)
  }

  const clientImports = models
    .map((m) => `import { ${m.name}Client } from './${m.name}Client'`)
    .join('\n')

  return `\
${clientImports}

${exportLines.join('\n')}

export class RestApiClient {
${constructorProps.join('\n')}

  constructor(baseUrl: string) {
${constructorAssignments.join('\n')}
  }
}
`
}
```

---

### Step 10 — `packages/generator-rest-client/src/generate.ts`

Orchestrates writing all output files to the configured directory.

```ts
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateModelClient } from './code-generators/model-client'
import { generateModelTypes } from './code-generators/model-types'
import { generateRestApiClient } from './code-generators/rest-api-client'

export interface GenerateOptions {
  outputDir: string
  models: readonly DMMF.Model[]
  enums: readonly DMMF.DatamodelEnum[]
}

/**
 * Orchestrates file generation for the REST API client.
 *
 * For each model, emits:
 *   - {outputDir}/{ModelName}.ts       — TypeScript interfaces
 *   - {outputDir}/{ModelName}Client.ts — REST client class
 *
 * Also emits:
 *   - {outputDir}/index.ts             — barrel + RestApiClient class
 *
 * Enums get their own declarations prepended to the model types file
 * that references them (and to a shared enums.ts if any model uses enums).
 */
export async function generate(options: GenerateOptions): Promise<void> {
  const { outputDir, models, enums } = options

  // Ensure output directory exists
  await fs.mkdir(outputDir, { recursive: true })

  // Emit enum declarations to a shared file if any enums exist
  if (enums.length > 0) {
    const enumContent = generateEnumDeclarations(enums)
    await fs.writeFile(path.join(outputDir, 'enums.ts'), enumContent, 'utf-8')
  }

  // Emit per-model files
  for (const model of models) {
    const typesContent = generateModelTypes(model)
    await fs.writeFile(path.join(outputDir, `${model.name}.ts`), typesContent, 'utf-8')

    const clientContent = generateModelClient(model)
    await fs.writeFile(path.join(outputDir, `${model.name}Client.ts`), clientContent, 'utf-8')
  }

  // Emit the barrel index
  const indexContent = generateRestApiClient(models)
  await fs.writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8')
}

/**
 * Generates TypeScript `const enum` declarations for all DMMF enums.
 * Uses a regular `enum` (not `const enum`) for broader runtime compatibility.
 */
function generateEnumDeclarations(enums: readonly DMMF.DatamodelEnum[]): string {
  return enums
    .map((e) => {
      const values = e.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
      return `export enum ${e.name} {\n${values}\n}\n`
    })
    .join('\n')
}
```

Edge cases handled:
- `fs.mkdir(..., { recursive: true })` is idempotent if the directory already exists.
- Models with zero fields: the `generateModelTypes` function produces empty interface bodies `{}`.
- Enums are emitted to a dedicated `enums.ts` and are available via `import` if the user needs them. They are not automatically re-exported from the barrel (keeping the barrel focused on model types and clients). The enum types in interfaces still reference enum names — users must import from `./enums` if needed. This is an acceptable trade-off; a future improvement would add enum re-exports to the barrel.

