### Step 11 — `packages/generator-rest-client/src/generator.ts`

Wires up the Prisma generator protocol.

```ts
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generate'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'REST API Client',
      defaultOutput: './rest-client',
      version: '1.0.0',
    }
  },

  async onGenerate(options: GeneratorOptions): Promise<void> {
    const outputValue = options.generator.output?.value
    if (!outputValue) {
      throw new Error(
        'No output directory specified for @prisma/generator-rest-client. ' +
        'Please add `output = "./rest-client"` to the generator block in your schema.'
      )
    }

    // Resolve relative to the schema file directory
    const outputDir = path.isAbsolute(outputValue)
      ? outputValue
      : path.join(path.dirname(options.schemaPath), outputValue)

    await generate({
      outputDir,
      models: options.dmmf.datamodel.models,
      enums: options.dmmf.datamodel.enums,
    })
  },
})
```

Key design decisions:
- `output?.value` is used because `GeneratorConfig.output` is typed as `EnvValue | null` (confirmed in `packages/generator/src/configuration.ts` line 8).
- The output path is resolved relative to the schema file directory, which is the standard Prisma convention (same pattern as `client-generator-ts`).
- `options.generator.output?.value` is the resolved string value; `fromEnvVar` indicates if it came from an env variable but `value` holds the final string.

