```ts
export function toCamelPlural(name: string): string {
  const lower = name.charAt(0).toLowerCase() + name.slice(1)
  return pluralize(lower)
}

export function toUrlPath(name: string): string {
  const kebab = name.replace(/([A-Z])/g, (m, offset) =>
    offset === 0 ? m.toLowerCase() : '-' + m.toLowerCase(),
  )
  return pluralize(kebab)
}

export function pluralize(word: string): string {
  if (
    word.endsWith('y') &&
    !/[aeiou]y$/.test(word)
  ) {
    return word.slice(0, -1) + 'ies'
  }
  if (/(?:s|x|z|ch|sh)$/.test(word)) {
    return word + 'es'
  }
  return word + 's'
}
```

#### `packages/generator-rest-client/src/code-generators/model-types.ts`

```ts
import type * as DMMF from '@prisma/dmmf'

import { scalarToTs } from '../utils/prisma-type-map'

function fieldTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    base = 'unknown'
  }

  if (field.isList) {
    base = `${base}[]`
  }
  if (!field.isRequired) {
    base = `${base} | null`
  }
  return base
}

function fieldTsTypeNoNull(field: DMMF.Field): string {
  const t = fieldTsType(field)
  return t.replace(' | null', '')
}

export function generateModelTypes(model: DMMF.Model): string {
  const scalarAndEnumFields = model.fields.filter(
    (f) => f.kind === 'scalar' || f.kind === 'enum',
  )

  const baseFields = scalarAndEnumFields
    .map((f) => `  ${f.name}: ${fieldTsType(f)}`)
    .join('\n')

  // CreateInput: exclude auto-generated id fields (isId + hasDefaultValue)
  const createFields = scalarAndEnumFields
    .filter((f) => !(f.isId && f.hasDefaultValue))
    .map((f) => (f.isRequired ? `  ${f.name}: ${fieldTsType(f)}` : `  ${f.name}?: ${fieldTsType(f)}`))
    .join('\n')

  // UpdateInput: all non-id writable fields, all optional
  const updateFields = scalarAndEnumFields
    .filter((f) => !(f.isId && f.hasDefaultValue))
    .map((f) => `  ${f.name}?: ${fieldTsType(f)}`)
    .join('\n')

  // WhereUniqueInput: id + unique scalar fields (without null)
  const uniqueScalars = scalarAndEnumFields.filter((f) => f.isId || f.isUnique)
  const whereSource = uniqueScalars.length > 0 ? uniqueScalars : scalarAndEnumFields
  const whereFields = whereSource
    .map((f) => `  ${f.name}?: ${fieldTsTypeNoNull(f)}`)
    .join('\n')

  const sections = [
    `export interface ${model.name} {\n${baseFields}\n}`,
    `export interface ${model.name}CreateInput {\n${createFields}\n}`,
    `export interface ${model.name}UpdateInput {\n${updateFields}\n}`,
    `export interface ${model.name}WhereUniqueInput {\n${whereFields}\n}`,
  ]

  return sections.join('\n\n') + '\n'
}
```

