```ts
import type * as DMMF from '@prisma/dmmf'

import { toUrlPath } from '../utils/naming'

export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const urlPath = toUrlPath(name)

  return (
    `import type { ${name}, ${name}CreateInput, ${name}UpdateInput, ${name}WhereUniqueInput } from './${name}'\n` +
    `\n` +
    `export class ${name}Client {\n` +
    `  constructor(private readonly baseUrl: string) {}\n` +
    `\n` +
    `  async findMany(): Promise<${name}[]> {\n` +
    `    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`)\n` +
    `    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)\n` +
    `    return res.json() as Promise<${name}[]>\n` +
    `  }\n` +
    `\n` +
    `  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {\n` +
    `    const params = new URLSearchParams(where as Record<string, string>)\n` +
    `    const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`)\n` +
    `    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)\n` +
    `    const results = await res.json() as ${name}[]\n` +
    `    return results[0] ?? null\n` +
    `  }\n` +
    `\n` +
    `  async create(data: ${name}CreateInput): Promise<${name}> {\n` +
    `    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {\n` +
    `      method: 'POST',\n` +
    `      headers: { 'Content-Type': 'application/json' },\n` +
    `      body: JSON.stringify(data),\n` +
    `    })\n` +
    `    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)\n` +
    `    return res.json() as Promise<${name}>\n` +
    `  }\n` +
    `\n` +
    `  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {\n` +
    `    const id = Object.values(where)[0]\n` +
    `    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, {\n` +
    `      method: 'PUT',\n` +
    `      headers: { 'Content-Type': 'application/json' },\n` +
    `      body: JSON.stringify(data),\n` +
    `    })\n` +
    `    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)\n` +
    `    return res.json() as Promise<${name}>\n` +
    `  }\n` +
    `\n` +
    `  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {\n` +
    `    const id = Object.values(where)[0]\n` +
    `    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, { method: 'DELETE' })\n` +
    `    if (!res.ok) throw new Error(\`HTTP \${res.status}\`)\n` +
    `    return res.json() as Promise<${name}>\n` +
    `  }\n` +
    `}\n`
  )
}
```

Note: String concatenation is used instead of template literals because the output itself contains template literal syntax (backtick expressions). This avoids the need for escaping.

#### `packages/generator-rest-client/src/code-generators/rest-api-client.ts`

```ts
import type * as DMMF from '@prisma/dmmf'

import { toCamelPlural } from '../utils/naming'

export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  if (models.length === 0) {
    return '// No models found in schema\n'
  }

  const importLines = models.map((m) => `import { ${m.name}Client } from './${m.name}Client'`).join('\n')

  const reExportLines = models
    .flatMap((m) => [
      `export type { ${m.name}, ${m.name}CreateInput, ${m.name}UpdateInput, ${m.name}WhereUniqueInput } from './${m.name}'`,
      `export { ${m.name}Client } from './${m.name}Client'`,
    ])
    .join('\n')

  const propDeclarations = models
    .map((m) => `  readonly ${toCamelPlural(m.name)}: ${m.name}Client`)
    .join('\n')

  const propAssignments = models
    .map((m) => `    this.${toCamelPlural(m.name)} = new ${m.name}Client(baseUrl)`)
    .join('\n')

  return (
    importLines +
    '\n\n' +
    reExportLines +
    '\n\n' +
    `export class RestApiClient {\n` +
    propDeclarations +
    '\n\n' +
    `  constructor(baseUrl: string) {\n` +
    propAssignments +
    '\n' +
    `  }\n` +
    `}\n`
  )
}
```

