Entry point: registers `generatorHandler` (making this runnable as a subprocess) and re-exports the `generate` function for programmatic use:

```typescript
import { generatorHandler } from '@prisma/generator-helper'
import type { GeneratorConfig, GeneratorManifest } from '@prisma/generator'

import { generate } from './generate'

export { generate }

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'REST API Client',
      defaultOutput: './rest-client',
      version: '1.0.0',
    }
  },

  async onGenerate(options) {
    await generate(options)
  },
})
