### Step 6 — `packages/generator-rest-client/src/utils/naming.ts`

Name utilities for consistent casing and URL paths. Uses DMMF `ModelMapping.plural` (already computed by Prisma) for URL paths:

```typescript
/** Converts a PascalCase model name to a lowercase URL path segment (e.g. "UserProfile" → "user-profiles"). */
export function toUrlPath(plural: string): string {
  // DMMF plural is already the correct English plural in camelCase (e.g. "users", "userProfiles")
  return plural
    .replace(/([A-Z])/g, (char) => `-${char.toLowerCase()}`)
    .replace(/^-/, '')
}

/** Converts a model name to a camelCase property name (e.g. "UserProfile" → "userProfiles"). */
export function toPropName(plural: string): string {
  return plural.charAt(0).toLowerCase() + plural.slice(1)
}
```

