### Step 7 — `packages/generator-rest-client/src/code-generators/model-types.ts`

Generates the TypeScript interfaces file for a single model. Only scalar and enum fields are included (relations are excluded from the base interface):

```typescript
import type { DMMF } from '@prisma/dmmf'
import { mapPrismaScalarToTs } from '../utils/prisma-type-map'

/** Returns the TypeScript type string for a single DMMF field. */
function fieldTsType(field: DMMF.Field): string {
  const base = field.kind === 'scalar' || field.kind === 'unsupported'
    ? mapPrismaScalarToTs(field.type)
    : field.type  // enum name

  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/** Returns true if the field should appear in the base model interface. */
function isDataField(field: DMMF.Field): boolean {
  return field.kind !== 'object'
}

/** Returns true if the field is part of the unique identifier (id or unique). */
function isUniqueField(field: DMMF.Field): boolean {
  return field.isId || field.isUnique
}

/**
 * Returns true if the field should be omitted from CreateInput:
 * auto-generated fields (@id @default, @updatedAt, or @default with a function).
 */
function isAutoField(field: DMMF.Field): boolean {
  if (!field.hasDefaultValue) return false
  const def = field.default
  // autoincrement(), now(), cuid(), uuid(), etc. are objects with `name`
  return typeof def === 'object' && def !== null && !Array.isArray(def) && 'name' in def
}

/** Generates the types file content for a model. */
export function generateModelTypes(
  model: DMMF.Model,
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const enumNames = new Set(enums.map((e) => e.name))
  const dataFields = model.fields.filter(isDataField)

  // Base interface (all scalar/enum fields)
  const interfaceLines = dataFields.map((f) => {
    const type = fieldTsType(f)
    const optional = !f.isRequired ? '?' : ''
    // Only mark required non-nullable fields as non-optional; nullable fields use `| null` instead
    return `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldTsType(f)}`
  })

  // WhereUniqueInput (id + unique scalar fields)
  const uniqueFields = dataFields.filter(isUniqueField)
  const whereUniqueLines = uniqueFields.map((f) => {
    const base = field.kind === 'scalar' || field.kind === 'unsupported'
      ? mapPrismaScalarToTs(f.type)
      : f.type
    return `  ${f.name}?: ${base}`
  })

  // CreateInput (non-auto scalar fields; nullable fields are optional)
  const createFields = dataFields.filter((f) => !isAutoField(f) && !f.isReadOnly)
  const createLines = createFields.map((f) => {
    const base = field.kind === 'scalar' || field.kind === 'unsupported'
      ? mapPrismaScalarToTs(f.type)
      : f.type
    const type = f.isList ? `${base}[]` : base
    const isOptional = !f.isRequired || f.hasDefaultValue
    return `  ${f.name}${isOptional ? '?' : ''}: ${f.isRequired ? type : `${type} | null`}`
  })

  // UpdateInput (all createFields but always optional)
  const updateLines = createFields.map((f) => {
    const base = field.kind === 'scalar' || field.kind === 'unsupported'
      ? mapPrismaScalarToTs(f.type)
      : f.type
    const type = f.isList ? `${base}[]` : base
    return `  ${f.name}?: ${f.isRequired ? type : `${type} | null`}`
  })

  const { name } = model

  return [
    `export interface ${name} {`,
    ...interfaceLines,
    `}`,
    ``,
    `export interface ${name}WhereUniqueInput {`,
    ...whereUniqueLines,
    `}`,
    ``,
    `export interface ${name}CreateInput {`,
    ...createLines,
    `}`,
    ``,
    `export interface ${name}UpdateInput {`,
    ...updateLines,
    `}`,
  ].join('\n') + '\n'
}
```

> **Note during implementation**: The field type resolution logic above has a minor bug — `field` reference in the arrow function should be `f`. Fix this during implementation — it's a copy-paste artifact in the plan. The correct pattern consistently uses the parameter `f` (not `field`). The plan agent's version in the saved output has the corrected version.

