### Step 8 — `packages/generator-rest-client/src/code-generators/model-client.ts`

Generates the `XxxClient` class with five CRUD methods using `fetch`. The URL path is derived from `DMMF.Mappings.modelOperations[n].plural`:

```typescript
import type { DMMF } from '@prisma/dmmf'
import { toUrlPath } from '../utils/naming'

/** Generates the client class file for a single model. */
export function generateModelClient(model: DMMF.Model, plural: string): string {
  const { name } = model
  const urlPath = toUrlPath(plural)

  return `\
import type { ${name}, ${name}WhereUniqueInput, ${name}CreateInput, ${name}UpdateInput } from './${name}'

export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`)
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const params = new URLSearchParams(where as Record<string, string>)
    const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`)
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    const results = await res.json() as ${name}[]
    return results[0] ?? null
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}
`
}
```

---

### Step 9 — `packages/generator-rest-client/src/code-generators/rest-api-client.ts`

Generates the top-level `RestApiClient` class and the barrel `index.ts`:

```typescript
import { toPropName } from '../utils/naming'

interface ModelEntry {
  name: string
  plural: string
}

/** Generates the top-level RestApiClient class source. */
export function generateRestApiClient(models: ModelEntry[]): string {
  const imports = models
    .map((m) => `import { ${m.name}Client } from './${m.name}Client'`)
    .join('\n')

  const props = models
    .map((m) => `  readonly ${toPropName(m.plural)}: ${m.name}Client`)
    .join('\n')

  const assignments = models
    .map((m) => `    this.${toPropName(m.plural)} = new ${m.name}Client(baseUrl)`)
    .join('\n')

  return `\
${imports}

export class RestApiClient {
${props}

  constructor(baseUrl: string) {
${assignments}
  }
}
`
}

/** Generates the index barrel file that re-exports everything. */
export function generateIndex(models: ModelEntry[]): string {
  const typeExports = models
    .map(
      (m) =>
        `export type { ${m.name}, ${m.name}WhereUniqueInput, ${m.name}CreateInput, ${m.name}UpdateInput } from './${m.name}'`,
    )
    .join('\n')

  const clientExports = models
    .map((m) => `export { ${m.name}Client } from './${m.name}Client'`)
    .join('\n')

  return `\
${typeExports}
${clientExports}
export { RestApiClient } from './RestApiClient'
`
}
```

