### Step 10 — `packages/generator-rest-client/src/generate.ts`

Orchestrates generation: iterates models, calls code generators, writes files to disk:

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { generateModelTypes } from './code-generators/model-types'
import { generateModelClient } from './code-generators/model-client'
import { generateRestApiClient, generateIndex } from './code-generators/rest-api-client'

/** Writes the full REST client to `outputDir`, creating it if necessary. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('generator-rest-client: output directory is required')
  }

  const { datamodel, mappings } = options.dmmf
  const { models, enums } = datamodel

  // Build a map from model name → plural (from DMMF mappings)
  const pluralMap = new Map<string, string>(
    mappings.modelOperations.map((m) => [m.model, m.plural]),
  )

  await fs.rm(outputDir, { recursive: true, force: true })
  await fs.mkdir(outputDir, { recursive: true })

  const modelEntries: Array<{ name: string; plural: string }> = []

  for (const model of models) {
    const plural = pluralMap.get(model.name) ?? `${model.name.toLowerCase()}s`
    modelEntries.push({ name: model.name, plural })

    // <Model>.ts  — interfaces and input types
    await fs.writeFile(
      path.join(outputDir, `${model.name}.ts`),
      generateModelTypes(model, enums),
    )

    // <Model>Client.ts  — CRUD fetch class
    await fs.writeFile(
      path.join(outputDir, `${model.name}Client.ts`),
      generateModelClient(model, plural),
    )
  }

  // RestApiClient.ts  — top-level composite client
  await fs.writeFile(
    path.join(outputDir, 'RestApiClient.ts'),
    generateRestApiClient(modelEntries),
  )

  // index.ts  — barrel re-exports
  await fs.writeFile(
    path.join(outputDir, 'index.ts'),
    generateIndex(modelEntries),
  )
}
```

