describe('generate()', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'prisma-rest-client-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  it('creates output directory and all expected files', async () => {
    await generate(makeOptions(tmpDir))

    const files = await fs.readdir(tmpDir)
    expect(files).toContain('User.ts')
    expect(files).toContain('UserClient.ts')
    expect(files).toContain('Post.ts')
    expect(files).toContain('PostClient.ts')
    expect(files).toContain('RestApiClient.ts')
    expect(files).toContain('index.ts')
  })

  it('generates correct User interface', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'User.ts'), 'utf8')
    expect(content).toContain('export interface User {')
    expect(content).toContain('id: number')
    expect(content).toContain('email: string')
    expect(content).toContain('name?: string | null')
    // relation field must not appear in the base interface
    expect(content).not.toContain('posts')
  })

  it('generates WhereUniqueInput with id and unique fields', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'User.ts'), 'utf8')
    expect(content).toContain('export interface UserWhereUniqueInput {')
    expect(content).toContain('id?: number')
    expect(content).toContain('email?: string')
  })

  it('generates CreateInput without auto-generated id', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'User.ts'), 'utf8')
    expect(content).toContain('export interface UserCreateInput {')
    // id has @default(autoincrement()) → excluded from CreateInput
    expect(content).not.toMatch(/UserCreateInput \{[^}]*\bid\b/)
    expect(content).toContain('email: string')
  })

  it('generates UserClient with CRUD methods', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'UserClient.ts'), 'utf8')
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('async findMany(): Promise<User[]>')
    expect(content).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(content).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(content).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(content).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
    // URL path should use the plural from DMMF mappings
    expect(content).toContain('/users')
  })

  it('generates RestApiClient composing all model clients', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'RestApiClient.ts'), 'utf8')
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('readonly users: UserClient')
    expect(content).toContain('readonly posts: PostClient')
    expect(content).toContain('this.users = new UserClient(baseUrl)')
    expect(content).toContain('this.posts = new PostClient(baseUrl)')
  })

  it('generates barrel index.ts re-exporting everything', async () => {
    await generate(makeOptions(tmpDir))

    const content = await fs.readFile(path.join(tmpDir, 'index.ts'), 'utf8')
    expect(content).toContain("export type { User,")
    expect(content).toContain("export { UserClient }")
    expect(content).toContain("export { RestApiClient } from './RestApiClient'")
  })

  it('overwrites existing output directory on re-run', async () => {
    // First run
    await generate(makeOptions(tmpDir))
    // Second run should not throw and should produce the same files
    await generate(makeOptions(tmpDir))

    const files = await fs.readdir(tmpDir)
    expect(files).toContain('index.ts')
  })
})
