import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  BigInt: 'number',
  Float: 'number',
  Decimal: 'number',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a DMMF scalar or enum field to its TypeScript type string. */
export function fieldToTsType(field: DMMF.Field): string {
  if (field.kind === 'scalar') {
    return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }
  if (field.kind === 'enum') {
    return field.type
  }
  return 'unknown'
}

/**
 * Returns true for fields that are automatically managed by the database or
 * Prisma (auto-increment IDs, `@updatedAt` timestamps, etc.) and should
 * therefore be excluded from `CreateInput` and `UpdateInput`.
 */
export function isAutoManagedField(field: DMMF.Field): boolean {
  if (field.isUpdatedAt) return true
  if (field.isId && field.hasDefaultValue) return true
  return false
}

/** Returns true for relation fields (`kind === 'object'`). */
export function isRelationField(field: DMMF.Field): boolean {
  return field.kind === 'object'
}

