import type * as DMMF from '@prisma/dmmf'

/** Converts a camelCase or PascalCase string to kebab-case for use in URL paths. */
function toKebabCase(str: string): string {
  return str.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()
}

/**
 * Generates the content of `<Model>Client.ts`, which contains a class with
 * typed `fetch`-based CRUD methods targeting a REST endpoint derived from the
 * model's plural mapping name.
 */
export function generateModelClientFile(model: DMMF.Model, pluralName: string): string {
  const name = model.name
  const urlSegment = toKebabCase(pluralName)

  return `\
import type { ${name}, ${name}WhereUniqueInput, ${name}CreateInput, ${name}UpdateInput } from './${name}'

export class ${name}Client {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl.replace(/\\/$/, '')
  }

  async findMany(): Promise<${name}[]> {
    const response = await fetch(\`\${this.#baseUrl}/${urlSegment}\`)
    if (!response.ok) throw new Error(\`HTTP \${response.status} on GET /${urlSegment}\`)
    return response.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const id = Object.values(where)[0]
    const response = await fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`)
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`HTTP \${response.status} on GET /${urlSegment}/\${id}\`)
    return response.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${urlSegment}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`HTTP \${response.status} on POST /${urlSegment}\`)
    return response.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const response = await fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`HTTP \${response.status} on PUT /${urlSegment}/\${id}\`)
    return response.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = Object.values(where)[0]
    const response = await fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`, { method: 'DELETE' })
    if (!response.ok) throw new Error(\`HTTP \${response.status} on DELETE /${urlSegment}/\${id}\`)
    return response.json() as Promise<${name}>
  }
}
`
}

