/** Model name paired with the camelCase property name used on `RestApiClient`. */
export type ModelEntry = {
  modelName: string
  propertyName: string
}

/**
 * Generates the content of `RestApiClient.ts`, a top-level class that
 * composes all per-model client instances under camelCase property names.
 */
export function generateRestApiClientFile(models: ModelEntry[]): string {
  const imports = models
    .map((m) => `import { ${m.modelName}Client } from './${m.modelName}Client'`)
    .join('\n')

  const properties = models.map((m) => `  readonly ${m.propertyName}: ${m.modelName}Client`).join('\n')

  const assignments = models
    .map((m) => `    this.${m.propertyName} = new ${m.modelName}Client(baseUrl)`)
    .join('\n')

  return `\
${imports}

export class RestApiClient {
${properties}

  constructor(baseUrl: string) {
${assignments}
  }
}
`
}

