import { describe, expect, it } from 'vitest'

import { fieldToTsType, isAutoManagedField, isRelationField } from './field-type-mapper'
import { generateIndexFile } from './generate-index'
import { generateModelClientFile } from './generate-model-client'
import { generateModelFile } from './generate-model'
import { generateRestApiClientFile } from './generate-rest-api-client'

// ---------------------------------------------------------------------------
// Minimal DMMF field factory
// ---------------------------------------------------------------------------

type PartialField = {
  name: string
  kind: 'scalar' | 'object' | 'enum' | 'unsupported'
  type: string
  isRequired?: boolean
  isId?: boolean
  isUnique?: boolean
  isReadOnly?: boolean
  hasDefaultValue?: boolean
  isUpdatedAt?: boolean
  isList?: boolean
}

function makeField(partial: PartialField) {
  return {
    name: partial.name,
    kind: partial.kind,
    type: partial.type,
    isRequired: partial.isRequired ?? true,
    isId: partial.isId ?? false,
    isUnique: partial.isUnique ?? false,
    isReadOnly: partial.isReadOnly ?? false,
    hasDefaultValue: partial.hasDefaultValue ?? false,
    isUpdatedAt: partial.isUpdatedAt ?? false,
    isList: partial.isList ?? false,
    dbName: null,
  } as const
}

function makeModel(name: string, fields: ReturnType<typeof makeField>[]) {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as const
}

// ---------------------------------------------------------------------------
// fieldToTsType
// ---------------------------------------------------------------------------

describe('fieldToTsType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['BigInt', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
  ])('maps scalar %s to TypeScript %s', (prismaType, tsType) => {
    const field = makeField({ name: 'x', kind: 'scalar', type: prismaType })
    expect(fieldToTsType(field)).toBe(tsType)
  })

  it('returns the enum name for enum fields', () => {
    const field = makeField({ name: 'role', kind: 'enum', type: 'Role' })
    expect(fieldToTsType(field)).toBe('Role')
  })

  it('returns "unknown" for unsupported kinds', () => {
    const field = makeField({ name: 'rel', kind: 'object', type: 'Post' })
    expect(fieldToTsType(field)).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// isAutoManagedField
// ---------------------------------------------------------------------------

describe('isAutoManagedField', () => {
  it('returns true for @updatedAt fields', () => {
    const field = makeField({ name: 'updatedAt', kind: 'scalar', type: 'DateTime', isUpdatedAt: true })
    expect(isAutoManagedField(field)).toBe(true)
  })

  it('returns true for ID fields with a default value', () => {
    const field = makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true, hasDefaultValue: true })
    expect(isAutoManagedField(field)).toBe(true)
  })

  it('returns false for a regular required field', () => {
    const field = makeField({ name: 'title', kind: 'scalar', type: 'String' })
    expect(isAutoManagedField(field)).toBe(false)
  })
})

// ---------------------------------------------------------------------------
// isRelationField
// ---------------------------------------------------------------------------

describe('isRelationField', () => {
  it('returns true for object kind fields', () => {
    const field = makeField({ name: 'author', kind: 'object', type: 'User' })
    expect(isRelationField(field)).toBe(true)
  })

  it('returns false for scalar fields', () => {
    const field = makeField({ name: 'name', kind: 'scalar', type: 'String' })
    expect(isRelationField(field)).toBe(false)
  })
})

// ---------------------------------------------------------------------------
// generateModelFile
// ---------------------------------------------------------------------------

describe('generateModelFile', () => {
  const model = makeModel('Post', [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true, hasDefaultValue: true }),
    makeField({ name: 'title', kind: 'scalar', type: 'String' }),
    makeField({ name: 'content', kind: 'scalar', type: 'String', isRequired: false }),
    makeField({ name: 'published', kind: 'scalar', type: 'Boolean', hasDefaultValue: true }),
    makeField({ name: 'updatedAt', kind: 'scalar', type: 'DateTime', isUpdatedAt: true }),
    makeField({ name: 'author', kind: 'object', type: 'User' }),
  ])

  it('emits the base Model interface with scalar/enum fields only', () => {
    const output = generateModelFile(model)
    expect(output).toContain('export interface Post {')
    expect(output).toContain('id: number')
    expect(output).toContain('title: string')
    expect(output).toContain('content?: string | null')
    expect(output).not.toContain('author')
  })

  it('emits WhereUniqueInput with only the @id field', () => {
    const output = generateModelFile(model)
    expect(output).toContain('export interface PostWhereUniqueInput {')
    expect(output).toContain('id: number')
  })

  it('excludes auto-managed fields from CreateInput', () => {
    const output = generateModelFile(model)
    expect(output).toContain('export interface PostCreateInput {')
    expect(output).not.toMatch(/CreateInput \{[^}]*\bid:/)
    expect(output).not.toMatch(/CreateInput \{[^}]*updatedAt:/)
    expect(output).toContain('title: string')
  })

  it('makes all fields optional in UpdateInput', () => {
    const output = generateModelFile(model)
    expect(output).toContain('export interface PostUpdateInput {')
    expect(output).toContain('title?: string')
    expect(output).toContain('published?: boolean')
  })
})

// ---------------------------------------------------------------------------
// generateModelClientFile
// ---------------------------------------------------------------------------

describe('generateModelClientFile', () => {
  const model = makeModel('Post', [makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true })])

  it('imports from the correct model file', () => {
    const output = generateModelClientFile(model, 'posts')
    expect(output).toContain("import type { Post, PostWhereUniqueInput, PostCreateInput, PostUpdateInput } from './Post'")
  })

  it('uses kebab-case URL segments for multi-word plural names', () => {
    const output = generateModelClientFile(model, 'blogPosts')
    expect(output).toContain('/blog-posts')
  })

  it('generates all five CRUD methods', () => {
    const output = generateModelClientFile(model, 'posts')
    expect(output).toContain('async findMany()')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  it('uses native private class field for baseUrl', () => {
    const output = generateModelClientFile(model, 'posts')
    expect(output).toContain('readonly #baseUrl')
  })
})

// ---------------------------------------------------------------------------
// generateRestApiClientFile
// ---------------------------------------------------------------------------

describe('generateRestApiClientFile', () => {
  const entries = [
    { modelName: 'Post', propertyName: 'post' },
    { modelName: 'User', propertyName: 'user' },
  ]

  it('imports each model client', () => {
    const output = generateRestApiClientFile(entries)
    expect(output).toContain("import { PostClient } from './PostClient'")
    expect(output).toContain("import { UserClient } from './UserClient'")
  })

  it('declares typed readonly properties', () => {
    const output = generateRestApiClientFile(entries)
    expect(output).toContain('readonly post: PostClient')
    expect(output).toContain('readonly user: UserClient')
  })

  it('instantiates each client in the constructor', () => {
    const output = generateRestApiClientFile(entries)
    expect(output).toContain('this.post = new PostClient(baseUrl)')
    expect(output).toContain('this.user = new UserClient(baseUrl)')
  })
})

// ---------------------------------------------------------------------------
// generateIndexFile
// ---------------------------------------------------------------------------

describe('generateIndexFile', () => {
  const modelNames = ['Post', 'User']

  it('re-exports types for every model', () => {
    const output = generateIndexFile(modelNames)
    expect(output).toContain(
      "export type { Post, PostWhereUniqueInput, PostCreateInput, PostUpdateInput } from './Post'",
    )
    expect(output).toContain(
      "export type { User, UserWhereUniqueInput, UserCreateInput, UserUpdateInput } from './User'",
    )
  })

  it('re-exports client classes for every model', () => {
    const output = generateIndexFile(modelNames)
    expect(output).toContain("export { PostClient } from './PostClient'")
    expect(output).toContain("export { UserClient } from './UserClient'")
  })

  it('re-exports RestApiClient', () => {
    const output = generateIndexFile(modelNames)
    expect(output).toContain("export { RestApiClient } from './RestApiClient'")
  })
})

