import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateIndexFile } from './generate-index'
import { generateModelClientFile } from './generate-model-client'
import { generateModelFile } from './generate-model'
import { generateRestApiClientFile, type ModelEntry } from './generate-rest-api-client'

/** Resolves the generator `output` config to an absolute directory path. */
function resolveOutputDir(output: GeneratorConfig['output'], schemaPath: string): string {
  if (!output) {
    return path.join(path.dirname(schemaPath), 'rest-client')
  }
  const raw = output.fromEnvVar ? (process.env[output.fromEnvVar] ?? '') : (output.value ?? '')
  if (!raw) {
    return path.join(path.dirname(schemaPath), 'rest-client')
  }
  return path.isAbsolute(raw) ? raw : path.resolve(path.dirname(schemaPath), raw)
}

/** Converts a camelCase string to a lowercase camelCase property name. */
function toCamelCase(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options.generator.output, options.schemaPath)
  await fs.mkdir(outputDir, { recursive: true })

  const pluralByModel = new Map(options.dmmf.mappings.modelOperations.map((m) => [m.model, m.plural]))

  const modelEntries: ModelEntry[] = []

  for (const model of options.dmmf.datamodel.models) {
    const pluralName = pluralByModel.get(model.name) ?? `${model.name.toLowerCase()}s`

    await fs.writeFile(path.join(outputDir, `${model.name}.ts`), generateModelFile(model), 'utf-8')

    await fs.writeFile(
      path.join(outputDir, `${model.name}Client.ts`),
      generateModelClientFile(model, pluralName),
      'utf-8',
    )

    modelEntries.push({ modelName: model.name, propertyName: toCamelCase(model.name) })
  }

  await fs.writeFile(path.join(outputDir, 'RestApiClient.ts'), generateRestApiClientFile(modelEntries), 'utf-8')

  await fs.writeFile(
    path.join(outputDir, 'index.ts'),
    generateIndexFile(modelEntries.map((e) => e.modelName)),
    'utf-8',
  )
}

export function getManifest(): GeneratorManifest {
  return {
    prettyName: 'Prisma REST API Client Generator',
    defaultOutput: 'rest-client',
    version: '0.0.0',
    requiresEngines: [],
  }
}
